CREATE OR REPLACE FUNCTION fpb_get_sum_receipt_cancel (adt_date timestamp(0) , as_method CHAR) RETURNS integer AS $body$
DECLARE

  li_count integer;

BEGIN
  if as_method = 'ALL' then
    select  count(*)
    into STRICT    li_count
    from    sc_com_m_receipt
    where   to_date(entry_date) = adt_date
    and     receipt_status = '1'
;
  else
    select  count(*)
    into STRICT    li_count
    from    sc_com_m_receipt
    where   to_date(entry_date) = adt_date
    and     receipt_status = '1'
    and     money_type_id = as_method
;
    end if;
  return coalesce(li_count,0);
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
